import{_ as e,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"30. Staff Appraisal","description":"","frontmatter":{"title":"30. Staff Appraisal","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/education-pd/30-staff-appraisal.md","filePath":"ebas/has-managers-admin/health-allied-services/education-pd/30-staff-appraisal.md"}'),p={name:"ebas/has-managers-admin/health-allied-services/education-pd/30-staff-appraisal.md"};function o(i,a,n,l,f,d){return t(),s("div",null,[...a[0]||(a[0]=[r('<h1 id="_30-staff-appraisal" tabindex="-1">30. Staff Appraisal <a class="header-anchor" href="#_30-staff-appraisal" aria-label="Permalink to &quot;30. Staff Appraisal&quot;">​</a></h1><p><strong>30.1</strong> Where a system of staff appraisal does not currently exist at a workplace, the Employer may implement a performance appraisal process and the Employees will participate in that process, provided that:</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(a)</strong> the Employer first consults at the local level with staff and/or the HWU or other representative over a framework for the staff appraisal process it is seeking to introduce;</p><p><strong>(b)</strong> the staff appraisal process is not used as a disciplinary tool;</p><p><strong>(c)</strong> the staff appraisal process is intended to allow genuine feedback by both the Employer and Employee; and</p><p><strong>(d)</strong> the outcomes of the review are documented and confirmed and a written copy of the outcomes in given to the Employee.</p><p>Plain language terms: performance review, appraisal.</p>',8)])])}const h=e(p,[["render",o]]);export{m as __pageData,h as default};
